head.script:
	/**
	 * 화면 초기화에 필요한 로직을 수행한다. 
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, "ECSZZ2100000", {"initScreenCallback" : scwin.searchDatas});
	};

	/**
	 * 화면 초기 데이터들을 조회한다.
	 * @param
	 * @return
	 */
	scwin.searchDatas = function() {
		// 화면 오픈시 자동조회를 한다.
		comLib.setEnterKeyEvent(grpInqire, scwin.btnInqire_onclick);
		scwin.btnInqire_onclick();

		ibxClsCdNm.focus();
	};

	/**
	 * 조회조건에 맞게 data를 조회한다.
	 * @param
	 * @return
	 */
	scwin.btnInqire_onclick = function() {
		var requestData = {};

		dltClsCdList.removeAll();
		dltCmmnCdList.removeAll();

		txtCnt2.setValue("0");

		dmaInqireParam.set("useYn" , "N");
		requestData.dmaInqireParam = dmaInqireParam.getJSON();

		var option = {action : "zz/cmmncd/retrieveClsCd.do",
			reqData : requestData,
			resData : dltClsCdList,
			success : "scwin.inqireClsCdCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqireClsCdCallback = function(resBody) {
		if (resBody.message.code == 'success') {
			if (dltClsCdList.getRowCount() > 0) {
				txtCnt1.setValue(dltClsCdList.getRowCount());
			}
			for (var idx = 0; idx < dltClsCdList.getRowCount(); idx++) {
				grdClsCdList.setCellReadOnly(idx, "clsCd", true);
			}
		} else {
			comLib.alert($p, "fail");
		}
	};

	/**
	 * 선택한 분류코드로 등록된 공통코드를 조회한다.
	 * @param <Int> row
	 * @param <Int> col
	 * @return
	 */
	scwin.grdClsCdList_oncellclick = function(row,col) {
		var clsCd = dltClsCdList.getCellData(row , "clsCd");

		dmaInqireParam.set("clsCd" , clsCd);

		if (clsCd == null || clsCd == "") {
			dltCmmnCdList.removeAll();
			return;
		}

		// 분류코드 셀을 클릭시에만 해당 공통코드를 검색한다.
		if (col == 0) {
			scwin.inqireClsCmmnCd();
		}
	};

	/**
	 * 공통코드를 조회한다.
	 * @param
	 * @return
	 */
	scwin.inqireClsCmmnCd = function () {
		var requestData = {};
		requestData.dmaInqireParam = dmaInqireParam.getJSON();
		requestData.dmaInqireParam.cmmnCdNm = dmaInqireParamCmmnCd.get("cmmnCdNm");

		var option = {
			action : "zz/cmmncd/retrieveCmmnCd.do",
			reqData : requestData,
			resData : dltCmmnCdList,
			success : "scwin.inqireClCmmnCdCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqireClCmmnCdCallback = function(resBody) {
		if (resBody.message.code == 'success'){
			txtCnt2.setValue(dltCmmnCdList.getRowCount());

			for (var idx = 0; idx < dltCmmnCdList.getRowCount(); idx++) {
				grdCmmnCdList.setCellReadOnly(idx, "clsCd", true);
				grdCmmnCdList.setCellReadOnly(idx, "cmmnCd", true);
			}
		} else{
			comLib.alert($p, "fail");
		}
	};

	/**
	 * 공통분류코드 행추가를 한다.
	 * @param
	 * @return
	 */
	scwin.btnAddRow1_onclick = function() {
		var newIndex = dltClsCdList.insertRow();

		// 사용여부는 자동으로 설정되게 한다.
		dltClsCdList.setCellData(newIndex, "useYn", "Y");

		grdClsCdList.setFocusedCell(newIndex, "clsCd", true);
	};

	/**
	 * 공통분류코드 행삭제를 한다.
	 * @param
	 * @return
	 */
	scwin.btnDelRow1_onclick = function() {
		var rowIndex = grdClsCdList.getFocusedRowIndex();
		var rowStatus = dltClsCdList.getRowStatus(rowIndex);

		if ( rowStatus != "C") {
			dltClsCdList.setCellData(rowIndex, "useYn", "N");
		} else {
			dltClsCdList.removeRow(rowIndex);
		}
	};

	/**
	 * 공통코드 행추가를 한다.
	 * @param
	 * @return
	 */
	scwin.btnAddRow2_onclick = function() {
		var newIndex = dltCmmnCdList.insertRow( );

		// 공통코드 추가 시 선택한 분류코드를 자동 설정해 준다.
		dltCmmnCdList.setCellData(newIndex, "clsCd", dmaInqireParam.get("clsCd"));
		// 사용여부는 자동으로 설정되게 한다.  
		dltCmmnCdList.setCellData(newIndex, "useYn", "Y");
		dltCmmnCdList.setCellData(newIndex, "sortOrdr", dltCmmnCdList.getRowCount());
		dltCmmnCdList.setCellData(newIndex, "sapLnkYn", "N");

		grdCmmnCdList.setFocusedCell(newIndex, "cmmnCd", true);
	};

	/**
	 * 공통코드 행삭제를 한다.
	 * @param
	 * @return
	 */
	scwin.btnDelRow2_onclick = function() {
		var rowIndex = grdCmmnCdList.getFocusedRowIndex();
		var rowStatus = dltCmmnCdList.getRowStatus(rowIndex);

		if (rowStatus != "C") {
			// 공통코드는 삭제를 할 수 없고 사용여부를 N으로 대체한다. 
			dltCmmnCdList.setCellData(rowIndex, "useYn", "N");
            grdCmmnCdList.setRowBackgroundColor(rowIndex, "#F7D9CC");
            dltCmmnCdList.modifyRowStatus(rowIndex, "D");
		} else {
			dltCmmnCdList.removeRow(rowIndex);
		}
	};

	/**
	 * 작업중이던 내용을 무시하고 초기화 한다.
	 * @param
	 * @return
	 */
	scwin.btnCancl_onclick = function() {
		dmaInqireParam.reset();

		dltClsCdList.removeAll();
		dltCmmnCdList.removeAll();

		scwin.btnInqire_onclick();
	};

	/**
	 * 공통분류코드, 공통코드 데이터를 수정/저장/삭제를 한다.
	 * @param
	 * @return
	 */
	scwin.btnSave_onclick = function() {
		if (dltClsCdList.getModifiedData() == "") {
			if (dltCmmnCdList.getModifiedData() == "") {
				// 처리할 데이터가 없습니다. 
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
				return;
			}
		}

		var cmmncnt = txtCnt2.getValue();

		for(var idx = 0; idx < dltCmmnCdList.getRowCount(); idx++) {
			if (cmmncnt == "0") { 
				dltCmmnCdList.setCellData(idx, "frstYn", "Y");
			} else {
				dltCmmnCdList.setCellData(idx, "frstYn", "N");
			}
		}

		var valInfo1 = [{id : "clsCd",  mandatory : true, minlength : 2}];
		var valInfo2 = [
			{id : "clsCd",  mandatory : true, minlength : 2},
			{id : "cmmnCd",  mandatory : true, minlength : 2, maxlength : 10}
		];

		if (utilLib.validateGridView(grdClsCdList, valInfo1) || utilLib.validateGridView(grdCmmnCdList, valInfo2)) {
			// 저장할것인지 confirm
			comLib.confirm($p, utilLib.getMessage("SCM.INFO.00239"), "scwin.saveConfirmCallback");
		}
	};

	/**
	 * 데이터 저장을 시행한다.
	 * @param
	 * @return
	 */
	scwin.saveConfirmCallback = function() {
		var requestData = {};
		requestData.dltClsCdList = dltClsCdList.getModifiedJSON();
		requestData.dltCmmnCdList = dltCmmnCdList.getModifiedJSON();

		var option = {action : "zz/cmmncd/saveCdList.do",
		reqData : requestData,
		success : "scwin.saveCdListCallback",
		savedToken : true,
		isShowMeg : false
	};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 데이터 저장 처리 후 다시 조회를 한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.saveCdListCallback = function(resBody) {
		//comLib.alert($p, resBody.message.code_name);
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00327"));

		//scwin.btnSearchonclick();
		//scwin.inqireClsCmmnCd();
		scwin.btnInqire_onclick();
	};

	/**
	 * 그리드의 입력이 끝난 후 이벤트
	 * @param <Int> row
	 * @param <Int> col
	 * @param <String> value
	 * @return
	 */	
	scwin.grdClsCdList_onafteredit = function(row, col, value) {
		var clsCd = dltClsCdList.getCellData(row, "clsCd");

		if(col == 0) {
			if (clsCd != "") {
				// 분류코드에 입력된 문자가 소문자일 경우 소문자는 대문자로 전환
				dltClsCdList.setCellData(row, "clsCd", clsCd.toUpperCase());
			}
		}
	};
